import{_ as t,o as a,c as r,ae as e}from"./chunks/framework.BzQXgbNp.js";const h=JSON.parse('{"title":"💤 AFK (掛機防護與狀態) 系統說明","description":"","frontmatter":{},"headers":[],"relativePath":"Mc-AFK-System.md","filePath":"Mc-AFK-System.md"}'),l={name:"Mc-AFK-System.md"};function s(n,o,i,c,d,g){return a(),r("div",null,[...o[0]||(o[0]=[e('<h1 id="💤-afk-掛機防護與狀態-系統說明" tabindex="-1">💤 AFK (掛機防護與狀態) 系統說明 <a class="header-anchor" href="#💤-afk-掛機防護與狀態-系統說明" aria-label="Permalink to &quot;💤 AFK (掛機防護與狀態) 系統說明&quot;">​</a></h1><p>伺服器提供自動 AFK (Away From Keyboard) 狀態檢測與無微不至的掛機防護機制，讓玩家在掛機時獲得全面的資產與生命安全保障。</p><hr><h2 id="⏱️-1-afk-自動判定機制" tabindex="-1">⏱️ 1. AFK 自動判定機制 <a class="header-anchor" href="#⏱️-1-afk-自動判定機制" aria-label="Permalink to &quot;⏱️ 1. AFK 自動判定機制&quot;">​</a></h2><ul><li><strong>靜止時間</strong>： <ul><li>當玩家在遊戲中原地<strong>靜止不動超過 10 分鐘 (600 秒)</strong> 時，系統會自動將玩家判定為 <strong>[AFK] 狀態</strong>。</li><li>系統會在聊天欄提示：<code>§b[Craft-Core] §e您已原地靜止超過 10 分鐘，進入 [AFK] 掛機防護狀態！</code></li></ul></li><li><strong>移動解除</strong>： <ul><li><strong>僅位移會解除 AFK</strong>：只要玩家的座標 $(X, Y, Z)$ 發生位移，系統會立即解除 AFK 狀態並提示：<code>§b[Craft-Core] §7您已移動，已解除 [AFK] 掛機防護狀態。</code></li><li><strong>轉動視角維持 AFK</strong>：僅轉動頭部視角或調整鏡頭方向（Yaw / Pitch）<strong>不會解除 AFK 狀態</strong>，方便玩家保持掛機防護。</li></ul></li></ul><hr><h2 id="🛡️-2-全方位掛機防護特權" tabindex="-1">🛡️ 2. 全方位掛機防護特權 <a class="header-anchor" href="#🛡️-2-全方位掛機防護特權" aria-label="Permalink to &quot;🛡️ 2. 全方位掛機防護特權&quot;">​</a></h2><p>處於 AFK 狀態的玩家享有以下安全防護：</p><ol><li><strong>完全無敵 (Immunity)</strong>： <ul><li>免疫<strong>所有來源</strong>的傷害，包含玩家 PVP 傷害、怪物攻擊、跌落傷害、窒息傷害、岩漿焚燒、水下溺水等。</li></ul></li><li><strong>防推擠 (No Push)</strong>： <ul><li>其他玩家或實體無法將處於 AFK 狀態的玩家推動或推離掛機位置（如推落懸崖或水坑）。</li></ul></li></ol><hr><h2 id="🏷️-3-afk-標籤顯示位置" tabindex="-1">🏷️ 3. [AFK] 標籤顯示位置 <a class="header-anchor" href="#🏷️-3-afk-標籤顯示位置" aria-label="Permalink to &quot;🏷️ 3. [AFK] 標籤顯示位置&quot;">​</a></h2><p>當玩家進入 AFK 狀態後，會在以下位置同步顯示顯眼的 <strong><code>[AFK]</code></strong> 前綴標籤：</p><ol><li><strong>聊天欄發言</strong>：發言名稱前附帶 <code>[AFK]</code> 標記。</li><li><strong>Tab 鍵玩家列表</strong>：開啟 Tab 列表時，名稱前方會加上灰色的 <code>[AFK]</code> 標記。</li><li><strong>玩家頭頂名稱 (Name Tag)</strong>：在遊戲實體頭頂直觀顯示 <code>[AFK]</code>。</li></ol>',13)])])}const F=t(l,[["render",s]]);export{h as __pageData,F as default};
